## Common patterns

### User profile header

Combine Avatar with text components to create a user profile header:

```jsx live-dev
const App = () => (
  <Stack direction="row" gap="400" alignItems="center">
    <Avatar
      firstName="Sarah"
      lastName="Johnson"
      src="https://i.pravatar.cc/150?img=5"
      size="md"
    />
    <Stack direction="column" gap="100">
      <Text fontSize="md" fontWeight="600">Sarah Johnson</Text>
      <Text fontSize="sm" color="neutral.11">Product Manager</Text>
    </Stack>
  </Stack>
)
```

### Comment or message list

Display avatars alongside user content in comments or messages:

```jsx live-dev
const App = () => {
  const comments = [
    { id: 1, author: { firstName: "Alex", lastName: "Chen" }, text: "Great work on this feature!", time: "2 hours ago" },
    { id: 2, author: { firstName: "Maria", lastName: "Garcia" }, text: "I agree, this is really helpful.", time: "1 hour ago" },
    { id: 3, author: { firstName: "James", lastName: "Wilson" }, text: "Looking forward to the next update.", time: "30 minutes ago" },
  ];

  return (
    <Stack direction="column" gap="600">
      {comments.map((comment) => (
        <Stack key={comment.id} direction="row" gap="400">
          <Avatar
            firstName={comment.author.firstName}
            lastName={comment.author.lastName}
            size="xs"
          />
          <Stack direction="column" gap="100" flex="1">
            <Stack direction="row" gap="200" alignItems="baseline">
              <Text fontSize="sm" fontWeight="600">
                {comment.author.firstName} {comment.author.lastName}
              </Text>
              <Text fontSize="xs" color="neutral.11">{comment.time}</Text>
            </Stack>
            <Text fontSize="sm">{comment.text}</Text>
          </Stack>
        </Stack>
      ))}
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Avatar
within your application. As the component's internal functionality is already
tested by Nimbus, these patterns help you verify your integration and
application-specific logic.

### Basic rendering tests

Verify the Avatar renders with expected elements and labels

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import { Avatar, NimbusProvider } from "@commercetools/nimbus";

describe("Avatar - Basic rendering", () => {
  it("renders avatar with initials", () => {
    render(
      <NimbusProvider>
        <Avatar firstName="John" lastName="Doe" />
      </NimbusProvider>
    );

    expect(screen.getByRole("figure")).toBeInTheDocument();
    expect(screen.getByLabelText(/John Doe/i)).toBeInTheDocument();
    expect(screen.getByText("JD")).toBeInTheDocument();
  });

  it("renders avatar with image", () => {
    render(
      <NimbusProvider>
        <Avatar
          firstName="Jane"
          lastName="Smith"
          src="https://example.com/avatar.jpg"
          alt="Jane Smith profile"
        />
      </NimbusProvider>
    );

    const image = screen.getByAltText("Jane Smith profile");
    expect(image).toBeInTheDocument();
    expect(image).toHaveAttribute("src", "https://example.com/avatar.jpg");
  });
});
```

### Size variant tests

Test different size options

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import { Avatar, NimbusProvider } from "@commercetools/nimbus";

describe("Avatar - Size variants", () => {
  it("renders different sizes correctly", () => {
    const { rerender } = render(
      <NimbusProvider>
        <Avatar firstName="John" lastName="Doe" size="2xs" />
      </NimbusProvider>
    );

    let avatar = screen.getByRole("figure");
    expect(avatar).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <Avatar firstName="John" lastName="Doe" size="xs" />
      </NimbusProvider>
    );

    avatar = screen.getByRole("figure");
    expect(avatar).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <Avatar firstName="John" lastName="Doe" size="md" />
      </NimbusProvider>
    );

    avatar = screen.getByRole("figure");
    expect(avatar).toBeInTheDocument();
  });
});
```

### Accessibility tests

Verify accessibility attributes and labeling

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import { Avatar, NimbusProvider } from "@commercetools/nimbus";

describe("Avatar - Accessibility", () => {
  it("has correct aria-label with full name", () => {
    render(
      <NimbusProvider>
        <Avatar firstName="Maria" lastName="Garcia" />
      </NimbusProvider>
    );

    const avatar = screen.getByLabelText(/Maria Garcia/i);
    expect(avatar).toBeInTheDocument();
    expect(avatar.tagName).toBe("FIGURE");
  });

  it("applies custom id for tracking", () => {
    const PERSISTENT_ID = "test-avatar-id";

    render(
      <NimbusProvider>
        <Avatar id={PERSISTENT_ID} firstName="John" lastName="Doe" />
      </NimbusProvider>
    );

    const avatar = screen.getByRole("figure");
    expect(avatar).toHaveAttribute("id", PERSISTENT_ID);
  });
});
```


